        "#,
        r###"error: must be a const-expression that resolves to a concrete integer scalar (`u32` or `i32`)
  ┌─ wgsl:3:36
  │
3 │             alias Bad = array<f32, length>;
  │                                    ^^^^^^ must resolve to `u32` or `i32`

"###,
    );

    check(
        "alias Bad = array<f32, 0>;",
