        fn f() {
            let x: array<u32, len> = arr;
        }
        ",
        r#"error: type `x` is not constructible
  ┌─ wgsl:5:17
  │
5 │             let x: array<u32, len> = arr;
  │                 ^ type is not constructible

"#,
    );
}

